# UNOPTIMIZED: N+1 Query Pattern
def get_items_for_reorder() -> dict[str, list]:
    # Step 1: Get item names
    item_names = frappe.db.sql_list(
        "SELECT name FROM tabItem WHERE is_stock_item=1..."
    )

    itemwise_reorder = {}
    # PROBLEM: Loop executes N queries (one per item)
    for item_code in item_names:
        # Query 1: Get item details - runs N times!
        item_data = frappe.db.get_value(
            "Item", item_code,
            ["name", "stock_uom", "description", ...],
            as_dict=True
        )

        # Query 2: Get reorder levels - runs N times!
        reorder_data = frappe.db.get_all(
            "Item Reorder",
            filters={"parent": item_code},
            fields=["warehouse", "warehouse_reorder_level", ...]
        )

        for rd in reorder_data:
            combined = {**item_data, **rd}
            itemwise_reorder.setdefault(item_code, []).append(combined)

    return itemwise_reorder
# Total queries: 1 + 2*N (e.g., 201 queries for 100 items)
